-- ================================================================
-- BepeAI — Configuração da Leticia Abreu com logo embutida
-- Executar no Supabase SQL Editor (Dashboard → SQL Editor → New query)
-- Substitua 'EMAIL_DA_LETICIA' pelo e-mail real dela no Supabase Auth.
-- ================================================================

UPDATE users
SET
  company_name = 'Leticia Abreu Recrutamento e Seleção',
  logo_base64  = 'data:image/png;base64,',
  template_overrides = '{"contrato":"clients/leticiaabreu/contrato","proposta_comercial":"clients/leticiaabreu/proposta_comercial","nda":"clients/leticiaabreu/nda","orcamento":"clients/leticiaabreu/orcamento","relatorio_final":"clients/leticiaabreu/relatorio_final"}'
WHERE email = 'recrutamento@leticiaabreu.com';

-- Verificação:
SELECT id, email, company_name,
       length(logo_base64) AS logo_bytes,
       template_overrides
FROM users
WHERE email = 'recrutamento@leticiaabreu.com';
